import axios from "axios";
import React, { useState, useEffect } from "react";
import ReactPaginate from "react-paginate";
import Select from "react-select";

function DailyExpense() {
  const [expenses, setExpenses] = useState([]);
  const [amount, setAmount] = useState("");
  const [expenseDate, setExpenseDate] = useState("");
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [getAllExpenseHead, setAllExpenseHead] = useState([]);

  // Pagination states
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage] = useState(100);
  const [totalCount, setTotalCount] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [grandTotal, setGrandTotal] = useState(0);

  const [formData, setFormData] = useState({
    expense_head_id: "",
    expense_head_id_for_report: "",
    head_name: "",
    from_date: "",
    to_date: "",
    search: "",
  });

  // Fetch expenses with server-side pagination
  // const fetchExpenses = async (
  //   page = currentPage,
  //   limit = itemsPerPage,
  //   shouldLoad = true
  // ) => {
  //   if (shouldLoad) setLoading(true);
  //   try {
  //     // const response = await fetch(
  //     //   `${process.env.REACT_APP_API_URL}/api/daily/expense?page=${page}&limit=${limit}${
  //     //     formData.expense_head_id_for_report
  //     //       ? `&expense_head_id_for_report=${formData.expense_head_id_for_report}`
  //     //       : ""
  //     //   }`
  //     // );
  //      const response = await fetch(
  //       `${process.env.REACT_APP_API_URL}/api/daily/expense?page=${page}&limit=${limit}`
  //     );
  //     const data = await response.json();

  //     setExpenses(data.expenses);
  //     setTotalCount(data.totalCount);
  //     setTotalPages(data.totalPages);
  //     setGrandTotal(data.grandTotal);
  //     setCurrentPage(data.currentPage);
  //   } catch (error) {
  //     console.error("Error fetching expenses:", error);
  //   } finally {
  //     setLoading(false);
  //   }
  // };

  const fetchExpenses = async (
  page = currentPage,
  limit = itemsPerPage,
  shouldLoad = true
) => {
  if (shouldLoad) setLoading(true);
  try {
    let query = `page=${page}&limit=${limit}`;

    if (formData.expense_head_id_for_report) {
      query += `&expense_head_id_for_report=${formData.expense_head_id_for_report}`;
    }
    if (formData.from_date) {
      query += `&from_date=${formData.from_date}`;
    }
    if (formData.to_date) {
      query += `&to_date=${formData.to_date}`;
    }

    const response = await fetch(
      `${process.env.REACT_APP_API_URL}/api/daily/expense?${query}`
    );

    const data = await response.json();

    setExpenses(data.expenses);
    setTotalCount(data.totalCount);
    setTotalPages(data.totalPages);
    setGrandTotal(data.grandTotal);
    setCurrentPage(data.currentPage);
  } catch (error) {
    console.error("Error fetching expenses:", error);
  } finally {
    setLoading(false);
  }
};


  // Load expense heads
  useEffect(() => {
    axios
      .get(process.env.REACT_APP_API_URL + "/get-all-transactions-heads")
      .then((res) => {
        setAllExpenseHead(res.data.results);
      })
      .catch((err) => console.log(err));
  }, []);

  // Refetch when filter changes
  useEffect(() => {
    fetchExpenses(1, 100, false);
  }, [formData.expense_head_id_for_report, formData.to_date]);

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const method = editId ? "PUT" : "POST";
      const url = editId
        ? `${process.env.REACT_APP_API_URL}/api/daily/expense/${editId}`
        : `${process.env.REACT_APP_API_URL}/api/daily/expense`;

      await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          amount,
          expense_date: expenseDate,
          expense_head_id: formData.expense_head_id,
        }),
      });

      setAmount("");
      // setExpenseDate("");
      setFormData({ expense_head_id: "", head_name: "" });
      setEditId(null);

      // Refetch
      const pageToFetch = editId ? currentPage : 1;
      await fetchExpenses(pageToFetch, itemsPerPage, false);
    } catch (error) {
      console.error("Error submitting expense:", error);
    } finally {
      setLoading(false);
    }
  };

  // Edit expense
  const editExpense = (expense) => {
    setEditId(expense.id);
    setAmount(expense.amount);
    setExpenseDate(expense.expense_date?.slice(0, 10)); // format as yyyy-mm-dd
    setFormData({
      expense_head_id: expense.expense_head_id,
      head_name: expense.head_name,
    });
  };

  // Delete expense
  const deleteExpense = async (id) => {
    if (window.confirm("Are you sure you want to delete this expense?")) {
      setLoading(true);
      try {
        await fetch(`${process.env.REACT_APP_API_URL}/api/daily/expense/${id}`, {
          method: "DELETE",
        });

        const remainingItemsOnPage = expenses.length - 1;
        const pageToFetch =
          remainingItemsOnPage === 0 && currentPage > 1
            ? currentPage - 1
            : currentPage;

        await fetchExpenses(pageToFetch, itemsPerPage, false);
      } catch (error) {
        console.error("Error deleting expense:", error);
      } finally {
        setLoading(false);
      }
    }
  };

  // Handle page change
  const handlePageChange = (selectedPage) => {
    const newPage = selectedPage.selected + 1;
    fetchExpenses(newPage, itemsPerPage, false);
  };

  const startIndex = (currentPage - 1) * itemsPerPage + 1;
  const endIndex = Math.min(currentPage * itemsPerPage, totalCount);

  return (
    <div className="container" style={{ maxWidth: "1600px", marginTop: "20px" }}>
      <div className="card shadow-sm">
        <div className="card-body">
          {/* Form */}
          <form onSubmit={handleSubmit} className="mb-4">
            <div className="row g-3 align-items-end">
              <div className="col-md-3">
                <label htmlFor="expense_date" className="form-label fw-medium">
                  Date
                </label>
                <input
                  type="date"
                  required
                  value={expenseDate}
                  onChange={(e) => setExpenseDate(e.target.value)}
                  className="form-control"
                  id="expense_date"
                  disabled={loading}
                />
              </div>

              <div className="col-sm-3">
                 <label htmlFor="expense" className="form-label fw-medium">
                  Expense
                </label>
                <Select
                  id="expense_head_id"
                  name="expense_head_id"
                  value={
                    formData.expense_head_id
                      ? {
                          value: formData.expense_head_id,
                          label: formData.head_name,
                        }
                      : null
                  }
                  options={[
                    { value: "", label: "Select Head" },
                    ...getAllExpenseHead.map((expense) => ({
                      value: expense.id,
                      label: expense.head_name,
                    })),
                  ]}
                  onChange={(selectedOption) => {
                    setFormData({
                      expense_head_id: selectedOption.value,
                      head_name: selectedOption.label,
                    });
                  }}
                  placeholder="Select Expense Head"
                />
              </div>

              <div className="col-md-3">
                <label htmlFor="amount" className="form-label fw-medium">
                  Amount
                </label>
                <input
                  type="number"
                  step="0.01"
                  required
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  className="form-control"
                  id="amount"
                  disabled={loading}
                />
              </div>

              <div className="col-md-3">
                <button
                  type="submit"
                  className="btn btn-primary w-100"
                  disabled={loading}
                >
                  {loading ? (
                    <>{editId ? "Updating..." : "Adding..."}</>
                  ) : editId ? (
                    "Update Expense"
                  ) : (
                    "Add Expense"
                  )}
                </button>
              </div>
            </div>
          </form>

          {/* Summary */}
          <div className="row mb-3">
            <div className="col-md-6">
              <div className="alert alert-info mb-0">
                <strong>Total Records: </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm"></span>
                ) : (
                  totalCount.toLocaleString()
                )}
              </div>
            </div>
            <div className="col-md-6">
              <div className="alert alert-success mb-0">
                <strong>Grand Total: </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm"></span>
                ) : (
                  `${parseFloat(grandTotal || 0).toFixed(2)}`
                )}
              </div>
            </div>
          </div>

          {/* Range info */}
          <div className="row mb-3">
            <div className="col-md-6">
              <small className="text-muted">
                Showing {totalCount > 0 ? startIndex : 0} to {endIndex} of{" "}
                {totalCount} entries
              </small>
            </div>
          </div>



          {/* Filters */}
<div className="row g-3 mb-4">
  <div className="col-md-3">
    <label className="form-label fw-medium">From Date</label>
    <input
      type="date"
      className="form-control"
      value={formData.from_date}
      onChange={(e) =>
        setFormData({ ...formData, from_date: e.target.value })
      }
    />
  </div>
  <div className="col-md-3">
    <label className="form-label fw-medium">To Date</label>
    <input
      type="date"
      className="form-control"
      value={formData.to_date}
      onChange={(e) =>
        setFormData({ ...formData, to_date: e.target.value })
      }
    />
  </div>

  <div className="col-sm-3">
                 <label htmlFor="expense" className="form-label fw-medium">
                  Expense
                </label>
                <Select
                  id="expense_head_id_for_report"
                  name="expense_head_id_for_report"
                  value={
                    formData.expense_head_id_for_report
                      ? {
                          value: formData.expense_head_id_for_report,
                          label: formData.head_name,
                        }
                      : null
                  }
                  options={[
                    { value: "", label: "Select Head" },
                    ...getAllExpenseHead.map((expense) => ({
                      value: expense.id,
                      label: expense.head_name,
                    })),
                  ]}
                  onChange={(selectedOption) => {
                    setFormData({
                      expense_head_id_for_report: selectedOption.value,
                      head_name: selectedOption.label,
                    });
                  }}
                  placeholder="Select Expense Head"
                />
              </div>

  <div className="col-md-3 d-flex align-items-end">
    <button
      className="btn btn-secondary w-100"
      onClick={() => fetchExpenses(1, itemsPerPage, true)}
      disabled={loading}
    >
      Apply Filters
    </button>
  </div>
</div>


          {/* Table */}
          <div className="table-responsive">
            <table className="table table-hover table-bordered">
              <thead className="table-light">
                <tr>
                  <th>Sr.No</th>
                  <th>Amount</th>
                  <th>Date</th>
                  <th>Expense Head</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  <tr>
                    <td colSpan="5" className="text-center py-4">
                      <div className="spinner-border"></div>
                      <div className="mt-2">Loading expenses...</div>
                    </td>
                  </tr>
                ) : expenses.length === 0 ? (
                  <tr>
                    <td colSpan="5" className="text-center py-4">
                      No expenses found
                    </td>
                  </tr>
                ) : (
                  expenses.map((expense, index) => (
                    <tr key={expense.id}>
                      <td>{startIndex + index}</td>
                      <td>{parseFloat(expense.amount).toFixed(2)}</td>
                      <td>
                       {(() => {
  const date = new Date(expense.expense_date);
  const day = String(date.getDate()).padStart(2, "0");
  const month = String(date.getMonth() + 1).padStart(2, "0"); // Month is 0-indexed
  const year = date.getFullYear();
  return `${day}-${month}-${year}`;
})()}

                      </td>
                      <td>{expense.head_name}</td>
                      <td>
                        <div className="btn-group">
                          <button
                            onClick={() => editExpense(expense)}
                            className="btn btn-warning btn-sm me-2"
                            disabled={loading}
                          >
                            Edit
                          </button>
                          {/* <button
                            onClick={() => deleteExpense(expense.id)}
                            className="btn btn-danger btn-sm"
                            disabled={loading}
                          >
                            Delete
                          </button> */}
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination */}
          {totalPages > 1 && !loading && (
            <div className="d-flex justify-content-center mt-4">
              <ReactPaginate
                previousLabel="← Previous"
                nextLabel="Next →"
                breakLabel="..."
                pageCount={totalPages}
                marginPagesDisplayed={2}
                pageRangeDisplayed={3}
                onPageChange={handlePageChange}
                forcePage={currentPage - 1}
                containerClassName="pagination mb-0"
                pageClassName="page-item"
                pageLinkClassName="page-link"
                previousClassName="page-item"
                previousLinkClassName="page-link"
                nextClassName="page-item"
                nextLinkClassName="page-link"
                breakClassName="page-item"
                breakLinkClassName="page-link"
                activeClassName="active"
                disabledClassName="disabled"
              />
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default DailyExpense;
