import axios from "axios";
import React, { useState, useEffect } from "react";
import Select from "react-select";

function AddTransaction() {
  const [payments, setPayments] = useState([]);
  const [getAmount, setAmount] = useState("");
  const [amountDate, setAmountDate] = useState("");
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [getAllBanks, setAllBanks] = useState([]);
  const [selectedValue, setSelectedValue] = useState("");
  const [getAllHeads, setAllHeads] = useState([]);
  
  // Add state for closing balance
  const [closingBalanceBeforeDate, setClosingBalanceBeforeDate] = useState(0);
  const [currentBalance, setCurrentBalance] = useState(0);

  const [formData, setFormData] = useState({
    bank_id_for_report: "",
    head_id_for_report: "",
  });

  // Add filter states (frontend only)
  const [filters, setFilters] = useState({
    date_from: "",
    date_to: "",
    search: ""
  });

  // Fetch all payments (no pagination)
  const fetchPayments = async (bank_id, shouldLoad = true) => {
    if (shouldLoad) setLoading(true);
    try {
      // Build query parameters (only backend filters)
      const params = new URLSearchParams();
      if (bank_id) params.append('bank_id', bank_id);
      if (filters.date_from) {
        params.append('date_from', filters.date_from);
      }else{
          params.append('date_from', amountDate);
      }
      if (filters.date_to) params.append('date_to', filters.date_to);

      const response = await fetch(
        `${process.env.REACT_APP_API_URL}/api/payments/bank/transactions?${params}`
      );
      const data = await response.json();

      // Handle the API response structure
      setPayments(data.transactions || []);
      
      // Set the closing balance before date
      setClosingBalanceBeforeDate(data.closingBalanceBeforeDate || 0);
      setCurrentBalance(data.currentBalance || 0);
      
    } catch (error) {
      console.error("Error fetching payments:", error);
      // Set safe defaults on error
      setPayments([]);
      setClosingBalanceBeforeDate(0);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const fetchBanks = () => {
      axios
        .get(process.env.REACT_APP_API_URL + "/get-all-banks")
        .then((res) => {
          setAllBanks(res.data.results || []);
        })
        .catch((err) => {
          console.log(err);
          setAllBanks([]);
        });
    };
    fetchBanks();
  }, []);

  useEffect(() => {
    const getHeads = () => {
      axios
        .get(process.env.REACT_APP_API_URL + "/get-all-transactions-heads")
        .then((res) => {
          setAllHeads(res.data.results || []);
        })
        .catch((err) => {
          console.log(err);
          setAllHeads([]);
        });
    };
    getHeads();
  }, []);

  // Add effect for date filter changes (backend filters)
  useEffect(() => {
    if(formData.bank_id_for_report !== '') {
      fetchPayments(formData.bank_id_for_report, false);
    }
  }, [filters.date_from, filters.date_to, formData.bank_id_for_report, amountDate]);

  const handleChange = (event) => {
    setSelectedValue(event.target.value);
  };

  // Handle filter changes
  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: value
    }));
  };

  // Clear filters function
  const clearFilters = () => {
    setFilters({
      date_from: "",
      date_to: "",
      search: ""
    });
  };

  // Frontend search filtering function
  const getFilteredPayments = () => {
    if (!payments) return [];
    
    if (!filters.search.trim()) {
      return payments;
    }

    const searchTerm = filters.search.toLowerCase().trim();
    
    return payments.filter(payment => {
      // Search in head name
      const headMatch = payment.head_name && 
        payment.head_name.toLowerCase().includes(searchTerm);
      
      // Search in bank name
      const bankMatch = payment.bank_name && 
        payment.bank_name.toLowerCase().includes(searchTerm);
      
      // Search in amount
      const amountMatch = payment.amount && 
        payment.amount.toString().includes(searchTerm);
      
      return headMatch || bankMatch || amountMatch;
    });
  };

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const method = editId ? "PUT" : "POST";
      const url = editId
        ? `${process.env.REACT_APP_API_URL}/api/payments/bank/transaction/${editId}`
        : `${process.env.REACT_APP_API_URL}/api/payments/bank/transactions`;

      await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          amount: getAmount,
          dates: amountDate,
          bank_id: formData.bank_id_for_report,
          head_id: formData.head_id_for_report,
          transaction_status: selectedValue,
        }),
      });

      // Reset form
      setAmount("");
      setSelectedValue("");
      setEditId(null);

      setFormData({
        ...formData,
        head_id_for_report: ""
      });

      // Refresh payments
      await fetchPayments(formData.bank_id_for_report, false);
    } catch (error) {
      console.error("Error submitting payment:", error);
    } finally {
      setLoading(false);
    }
  };

  // Edit payment
  const editPayment = (payment) => {
    setEditId(payment.id);
    setAmount(payment.amount);
    setAmountDate(payment.dates);
    setSelectedValue(payment.transaction_status || "");
    setFormData({ 
      ...formData, 
      bank_id_for_report: payment.bank_id,
      head_id_for_report: payment.head_id 
    });
  };

  // Delete payment
  const deletePayment = async (id) => {
    if (window.confirm("Are you sure you want to delete this payment?")) {
      setLoading(true);
      try {
        await fetch(`${process.env.REACT_APP_API_URL}/api/payments/${id}`, {
          method: "DELETE",
        });

        await fetchPayments(formData.bank_id_for_report, false);
      } catch (error) {
        console.error("Error deleting payment:", error);
      } finally {
        setLoading(false);
      }
    }
  };

  // Get filtered payments for display
  const filteredPayments = getFilteredPayments();

  // Calculate running balance for ledger format starting from closingBalanceBeforeDate
  const calculateRunningBalance = (transactions) => {
    let runningBalance = closingBalanceBeforeDate; // Start with closing balance before date
    return transactions.map((transaction) => {
      const amount = parseFloat(transaction.amount || 0);
      if (transaction.transaction_status === 'In') {
        runningBalance += amount;
      } else {
        runningBalance -= amount;
      }
      return {
        ...transaction,
        runningBalance: runningBalance
      };
    });
  };

  const transactionsWithBalance = calculateRunningBalance(filteredPayments || []);

  // Calculate totals for In and Out (from filtered payments)
  const totalIn = (filteredPayments || [])
    .filter(payment => payment.transaction_status === 'In')
    .reduce((sum, payment) => sum + parseFloat(payment.amount || 0), 0);

  const totalOut = (filteredPayments || [])
    .filter(payment => payment.transaction_status === 'Out')
    .reduce((sum, payment) => sum + parseFloat(payment.amount || 0), 0);

  return (
    <div>
      <div className="card shadow-sm">
        <div className="card-body">
          <form onSubmit={handleSubmit} className="mb-4">
            <div className="row g-3 align-items-end">
              <div className="col-md-2">
                <label htmlFor="amount_date" className="form-label fw-medium">
                  Date
                </label>
                <input
                  type="date"
                  required
                  value={amountDate}
                  onChange={(e) => setAmountDate(e.target.value)}
                  className="form-control"
                  id="amount_date"
                  disabled={loading}
                />
              </div>

              <div className="col-md-2">
                <label htmlFor="amount" className="form-label fw-medium">
                  Amount
                </label>
                <input
                  type="number"
                  step="0.01"
                  required
                  value={getAmount}
                  onChange={(e) => setAmount(e.target.value)}
                  className="form-control"
                  id="amount"
                  disabled={loading}
                />
              </div>

              <div className="col-sm-2">
                <label htmlFor="head_select" className="form-label fw-medium">
                  Head
                </label>
                <Select
                  id="head_select"
                  name="head_id_for_report"
                  value={
                    formData.head_id_for_report
                      ? {
                          value: formData.head_id_for_report,
                          label:
                            getAllHeads.find(
                              (head) => head.id === formData.head_id_for_report
                            )?.head_name || "",
                        }
                      : null
                  }
                  options={[
                    { value: "", label: "Select Head" },
                    ...getAllHeads.map((head) => ({
                      value: head.id,
                      label: head.head_name,
                    })),
                  ]}
                  onChange={(selectedOption) => {
                    setFormData({
                      ...formData,
                      head_id_for_report: selectedOption ? selectedOption.value : "",
                    });
                  }}
                  placeholder="Select Head"
                  isClearable
                />
              </div>

              <div className="col-sm-2">
                <label htmlFor="bank_select" className="form-label fw-medium">
                  Bank Accounts
                </label>
                <Select
                  id="bank_select"
                  name="bank_id_for_report"
                  value={
                    formData.bank_id_for_report
                      ? {
                          value: formData.bank_id_for_report,
                          label:
                            getAllBanks.find(
                              (bank) => bank.id === formData.bank_id_for_report
                            )?.bank_name || "",
                        }
                      : null
                  }
                  options={[
                    { value: "", label: "Select Bank Account" },
                    ...getAllBanks.map((bank) => ({
                      value: bank.id,
                      label: bank.bank_name,
                    })),
                  ]}
                  onChange={(selectedOption) => {
                    setFormData({
                      ...formData,
                      bank_id_for_report: selectedOption ? selectedOption.value : "",
                    });
                  }}
                  placeholder="Select Bank Account"
                  isClearable
                />
              </div>

              <div className="col-sm-2">
                <label htmlFor="status" className="form-label fw-medium">
                  Transaction Status
                </label>
                <select
                  id="inout-select"
                  value={selectedValue}
                  onChange={handleChange}
                  className="form-control"
                  required
                >
                  <option value="">-- Select --</option>
                  <option value="In">In</option>
                  <option value="Out">Out</option>
                </select>
              </div>

              <div className="col-md-2">
                <button
                  type="submit"
                  className="btn btn-primary w-100"
                  disabled={loading}
                >
                  {loading ? (
                    <>{editId ? "Updating..." : "Adding..."}</>
                  ) : editId ? (
                    "Update Transaction"
                  ) : (
                    "Add Transaction"
                  )}
                </button>
              </div>
            </div>
          </form>

          {/* Filter Section */}
          <div className="card bg-light mb-4">
            <div className="card-body">
              <h6 className="card-title mb-3">Filters</h6>
              <div className="row g-3 align-items-end justify-content-center">
                <div className="col-md-3">
                  <label htmlFor="date_from" className="form-label fw-medium">
                    Date From
                  </label>
                  <input
                    type="date"
                    name="date_from"
                    value={filters.date_from}
                    onChange={handleFilterChange}
                    className="form-control"
                    id="date_from"
                    disabled={loading}
                  />
                </div>

                <div className="col-md-3">
                  <label htmlFor="date_to" className="form-label fw-medium">
                    Date To
                  </label>
                  <input
                    type="date"
                    name="date_to"
                    value={filters.date_to}
                    onChange={handleFilterChange}
                    className="form-control"
                    id="date_to"
                    disabled={loading}
                  />
                </div>

                <div className="col-md-3">
                  <label htmlFor="search" className="form-label fw-medium">
                    Search
                  </label>
                  <input
                    type="text"
                    name="search"
                    value={filters.search}
                    onChange={handleFilterChange}
                    className="form-control"
                    id="search"
                    placeholder="Search transactions..."
                    disabled={loading}
                  />
                </div>

                <div className="col-md-2">
                  <button
                    type="button"
                    onClick={clearFilters}
                    className="btn btn-secondary w-100"
                    disabled={loading}
                  >
                    Clear Filters
                  </button>
                </div>
              </div>
            </div>
          </div>

          {/* Summary Section */}
          <div className="row mb-3">
            <div className="col-md-2">
              <div className="alert alert-info mb-0 text-center">
                <strong className="d-block">Total Transactions: </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                ) : (
                  filteredPayments.length.toLocaleString()
                )}
              </div>
            </div>
            <div className="col-md-2">
              <div className="alert alert-secondary mb-0 text-center">
                <strong className="d-block">Last Closing: </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                ) : (
                  `${closingBalanceBeforeDate.toFixed(2)}`
                )}
              </div>
            </div>
            <div className="col-md-2">
              <div className="alert alert-success mb-0 text-center">
                <strong className="d-block">Total In (Transaction): </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                ) : (
                  `${totalIn.toFixed(2)}`
                )}
              </div>
            </div>
            <div className="col-md-2">
              <div className="alert alert-danger mb-0 text-center">
                <strong className="d-block">Total Out (Transaction): </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                ) : (
                  `${totalOut.toFixed(2)}`
                )}
              </div>
            </div>
            <div className="col-md-2">
              <div className="alert alert-warning mb-0 text-center">
                <strong className="d-block">Transaction Balance: </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                ) : (
                  `${(totalIn - totalOut).toFixed(2)}`
                )}
              </div>
            </div>
            <div className="col-md-2">
              <div className="alert alert-primary mb-0 text-center">
                <strong className="d-block">Current Balance: </strong>
                {loading ? (
                  <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                ) : (
                  `${(currentBalance).toFixed(2)}`
                )}
              </div>
            </div>
          </div>

          {/* Showing entries info */}
          <div className="row mb-3">
            <div className="col-md-6">
              <small className="text-muted">
                Showing {filteredPayments.length} of {payments.length} total entries
                {filters.search && ` (filtered by "${filters.search}")`}
              </small>
            </div>
          </div>

          {/* Ledger Table */}
          <div className="table-responsive">
            <table className="table table-hover table-bordered">
              <thead className="table-light">
                <tr>
                  <th scope="col">Sr.No</th>
                  <th scope="col">Date</th>
                  <th scope="col">Head</th>
                  <th scope="col">Bank</th>
                  <th scope="col" className="text-success">In</th>
                  <th scope="col" className="text-danger">Out</th>
                  <th scope="col" className="text-primary">Balance</th>
                  <th scope="col">Actions</th>
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  <tr>
                    <td colSpan="8" className="text-center py-4">
                      <div className="mt-2">Loading transactions...</div>
                    </td>
                  </tr>
                ) : !filteredPayments || filteredPayments.length === 0 ? (
                  <>
                    {/* Opening Balance Row */}
                    {closingBalanceBeforeDate !== 0 && (
                      <tr className="table-info">
                        <td>-</td>
                        <td>-</td>
                        <td>Last Closing</td>
                        <td>-</td>
                        <td className="text-success fw-bold">
                          {closingBalanceBeforeDate.toFixed(2)}
                        </td>
                        <td className="text-danger fw-bold">-</td>
                        <td className="text-primary fw-bold">
                          {closingBalanceBeforeDate.toFixed(2)}
                        </td>
                        <td>-</td>
                      </tr>
                    )}
                    <tr>
                      <td colSpan="8" className="text-center py-4">
                        {filters.search ? `No transactions found matching "${filters.search}"` : "No transactions found"}
                      </td>
                    </tr>
                  </>
                ) : (
                  <>
                    {/* Opening Balance Row */}
                    {closingBalanceBeforeDate !== 0 && (
                      <tr className="table-info">
                        <td>-</td>
                        <td>-</td>
                       <td>Last Closing</td>
                        <td>-</td>
                        <td className="text-success fw-bold">
                          {closingBalanceBeforeDate.toFixed(2)}
                        </td>
                        <td className="text-danger fw-bold">-</td>
                        <td className="text-primary fw-bold">
                          {closingBalanceBeforeDate.toFixed(2)}
                        </td>
                        <td>-</td>
                      </tr>
                    )}
                    {/* Transaction Rows */}
                    {transactionsWithBalance.map((payment, index) => (
                      <tr key={payment.id}>
                        <td>{index + 1}</td>
                        <td>
                          {new Date(payment.dates)
                            .toLocaleString("en-GB", {
                              day: "2-digit",
                              month: "2-digit",
                              year: "numeric",
                            })
                            .replace(/\//g, "-")}
                        </td>
                          <td>{payment.head_name || "N/A"}</td>
                        <td>{payment.bank_name || "N/A"}</td>
                       
                        <td className="text-success fw-bold">
                          {payment.transaction_status === 'In' 
                            ? parseFloat(payment.amount || 0).toFixed(2) 
                            : '-'
                          }
                        </td>
                        <td className="text-danger fw-bold">
                          {payment.transaction_status === 'Out' 
                            ? parseFloat(payment.amount || 0).toFixed(2) 
                            : '-'
                          }
                        </td>
                        <td className="text-primary fw-bold">
                          {payment.runningBalance.toFixed(2)}
                        </td>
                        <td>
                          <div className="btn-group" role="group">
                            <button
                              onClick={() => editPayment(payment)}
                              className="btn btn-warning btn-sm me-2"
                              disabled={loading}
                            >
                              Edit
                            </button>
                            {/* <button
                              onClick={() => deletePayment(payment.id)}
                              className="btn btn-danger btn-sm"
                              disabled={loading}
                            >
                              Delete
                            </button> */}
                          </div>
                        </td>
                      </tr>
                    ))}
                  </>
                )}
              </tbody>
              {/* Summary Row */}
              {!loading && filteredPayments && filteredPayments.length > 0 && (
                <tfoot className="table-secondary">
                  <tr>
                    <td colSpan="4" className="fw-bold text-end">Totals:</td>
                    <td className="text-success fw-bold">{totalIn.toFixed(2)}</td>
                    <td className="text-danger fw-bold">{totalOut.toFixed(2)}</td>
                    <td className="text-primary fw-bold">{(closingBalanceBeforeDate + totalIn - totalOut).toFixed(2)}</td>
                    <td></td>
                  </tr>
                </tfoot>
              )}
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AddTransaction;